record.field:
# Generate Channels for Stations that don't have one
for record in records:
    if not record.channel_id:
        # Check if channel with same name exists to avoid duplicate
        existing_channel = env['slide.channel'].search([('name', '=', record.name)], limit=1)
        if existing_channel:
            record.write({'channel_id': existing_channel.id})
            existing_channel.write({'soc_station_id': record.id})
        else:
            channel = env['slide.channel'].create({
                'name': record.name,
                'is_published': True,
                'soc_station_id': record.id,
                'description': f"Training Path for Station: {record.name}",
                'enroll': 'public', 
                'channel_type': 'training',
                'promote_strategy': 'most_voted',
            })
            record.write({'channel_id': channel.id})
